import{state}from '../../state.js';import{fetchJson,loadWorkloadAlertConfig,saveWorkloadAlertConfig,loadWorkloadAlertHistory,loadNotificationChannels}from '../../api.js';import{escapeHtml,formatDate,show,hide}from '../../utils/dom.js';let allUserGroups=[];export function getAdminElements(){return{adminPanel:document.getElementById('adminPanel'),userList:document.getElementById('userList'),userGroupList:document.getElementById('userGroupList'),createUserGroupBtn:document.getElementById('createUserGroupBtn'),workloadAlertConfig:document.getElementById('workloadAlertConfig'),workloadAlertHistory:document.getElementById('workloadAlertHistory'),workloadAlertMsg:document.getElementById('workloadAlertMsg')}}export function renderAdminUI(){const{adminPanel,workloadAlertConfig}=getAdminElements();if (!adminPanel) return;if (state.isAdmin){show(adminPanel);if (workloadAlertConfig) show(workloadAlertConfig);loadAllUsers();loadUserGroupsList();initUserGroupUI();loadWorkloadAlertConfig();loadNotificationChannels();initChannelFormHandlers()}else{hide(adminPanel);if (workloadAlertConfig) hide(workloadAlertConfig)}}export async function loadAllUsers(){const{userList}=getAdminElements();if (!userList) return;try{const res=await fetchJson('/api/admin/users');state.allUsers=res.users||[];renderUserManagementPanel()}catch (err){console.error('加载用户列表失败:',err)}}export function renderUserManagementPanel(){const{userList}=getAdminElements();if (!userList) return;if (state.allUsers.length===0){userList.innerHTML='<div class="muted small">暂无用户</div>';return}userList.innerHTML=state.allUsers.map(user=>{const isCurrentUser=user.id===state.currentUser?.id;const roleClass=user.role==='admin'?'admin':'user';const roleLabel=user.role==='admin'?'管理员':'普通用户';const createdAt=user.createdAt?new Date(user.createdAt).toLocaleString('zh-CN'):'—';const lastLoginAt=user.lastLoginAt?new Date(user.lastLoginAt).toLocaleString('zh-CN'):'从未登录';const groupName=user.groupId?(allUserGroups.find(g=>g.id===user.groupId)?.name||'未知组'):'';return `<div class="user-item" data-user-id="${user.id}"><div class="user-item-info"><div class="user-item-name">${escapeHtml(user.name)}${isCurrentUser?'<span class="muted">(本人)</span>':''}${groupName?`<span class="user-group-badge">${escapeHtml(groupName)}</span>`:''}</div><div class="user-item-meta"><span class="user-role-badge ${roleClass}">${roleLabel}</span><span>注册:${createdAt}</span><span>最后登录:${lastLoginAt}</span></div></div><div class="user-item-actions">${!isCurrentUser?`<select class="user-role-select" data-user-id="${user.id}"><option value="user" ${user.role!=='admin'?'selected':''}>普通用户</option><option value="admin" ${user.role==='admin'?'selected':''}>管理员</option></select><select class="user-group-select" data-user-id="${user.id}" style="margin-left:8px;"><option value="">无</option>${allUserGroups.map(g=>`<option value="${g.id}" ${user.groupId===g.id?'selected':''}>${escapeHtml(g.name)}</option>`).join('')}</select><button class="ghost tiny update-role-btn" data-user-id="${user.id}" data-user-name="${escapeHtml(user.name)}" style="margin-left:8px;">更新角色</button><button class="ghost tiny update-group-btn" data-user-id="${user.id}" data-user-name="${escapeHtml(user.name)}">更新组</button>`:'<span class="muted small">当前用户</span>'}</div></div>`}).join('');userList.querySelectorAll('.update-role-btn').forEach(btn=>{btn.addEventListener('click',async ()=>{const userId=btn.dataset.userId;const userName=btn.dataset.userName;const select=userList.querySelector(`.user-role-select[data-user-id="${userId}"]`);const newRole=select.value;if (!confirm(`确定要将用户 "${userName}" 的角色修改为 ${newRole==='admin'?'管理员':'普通用户'}吗？`)){return}try{await fetchJson(`/api/users/${userId}/role`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({role:newRole})});alert('角色已更新');await loadAllUsers()}catch (err){alert('更新失败:'+err.message)}})});userList.querySelectorAll('.update-group-btn').forEach(btn=>{btn.addEventListener('click',async ()=>{const userId=btn.dataset.userId;const userName=btn.dataset.userName;const select=userList.querySelector(`.user-group-select[data-user-id="${userId}"]`);const groupId=select.value||null;const groupName=groupId?(allUserGroups.find(g=>g.id===groupId)?.name||'未知组'):'无';if (!confirm(`确定要将用户 "${userName}" 的组别修改为 ${groupName}吗？`)){return}try{await fetchJson(`/api/admin/users/${userId}/group`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({groupId})});alert('用户组已更新');await loadAllUsers();await loadUserGroupsList()}catch (err){alert('更新失败：'+err.message)}})})}export async function loadUserGroupsList(){try{const res=await fetchJson('/api/admin/user-groups');allUserGroups=res.groups||[];renderUserGroupList()}catch (err){console.error('加载用户组列表失败:',err)}}export function renderUserGroupList(){const{userGroupList}=getAdminElements();if (!userGroupList) return;if (allUserGroups.length===0){userGroupList.innerHTML='<div class="muted small">暂无用户组</div>';return}userGroupList.innerHTML=allUserGroups.map(group=>`<div class="user-group-item" data-group-id="${group.id}"><div class="user-group-item-info"><div class="user-group-item-name">${escapeHtml(group.name)}<span class="user-group-badge">${group.memberCount||0}名成员</span></div><div class="user-group-item-meta">${group.description?escapeHtml(group.description):'<span class="muted">无描述</span>'}</div></div><div class="user-group-item-actions"><button class="ghost tiny edit-group-btn" data-group-id="${group.id}">编辑</button><button class="danger tiny delete-group-btn" data-group-id="${group.id}">删除</button></div></div>`).join('');userGroupList.querySelectorAll('.edit-group-btn').forEach(btn=>{btn.addEventListener('click',()=>openUserGroupModal(btn.dataset.groupId))});userGroupList.querySelectorAll('.delete-group-btn').forEach(btn=>{btn.addEventListener('click',async ()=>{const groupId=btn.dataset.groupId;const group=allUserGroups.find(g=>g.id===groupId);if (!confirm(`确定要删除用户组 "${group.name}" 吗？`)) return;try{await fetchJson(`/api/admin/user-groups/${groupId}`,{method:'DELETE'});await loadUserGroupsList();await loadAllUsers()}catch (err){alert('删除失败：'+err.message)}})})}function openUserGroupModal(groupId=null){const modal=document.getElementById('userGroupModal');const title=document.getElementById('userGroupModalTitle');const form=document.getElementById('userGroupForm');const idInput=document.getElementById('userGroupId');const nameInput=document.getElementById('userGroupName');const descInput=document.getElementById('userGroupDescription');const membersDiv=document.getElementById('userGroupMembers');if (!modal) return;form.reset();idInput.value='';if (groupId){title.textContent='编辑用户组';const group=allUserGroups.find(g=>g.id===groupId);if (group){idInput.value=group.id;nameInput.value=group.name;descInput.value=group.description||''}}else{title.textContent='创建用户组'}if (state.allUsers&&state.allUsers.length>0){const groupMemberIds=groupId?(allUserGroups.find(g=>g.id===groupId)?.memberIds||[]):[];membersDiv.innerHTML=state.allUsers.map(user=>`<label style="display:flex;align-items:center;gap:8px;padding:4px 0;"><input type="checkbox" value="${user.id}" ${groupMemberIds.includes(user.id)?'checked':''}/><span>${escapeHtml(user.name)}${user.id===state.currentUser?.id?' (本人)':''}</span></label>`).join('')}show(modal)}export function initUserGroupUI(){const createBtn=document.getElementById('createUserGroupBtn');if (createBtn){createBtn.addEventListener('click',()=>openUserGroupModal())}const form=document.getElementById('userGroupForm');if (form){form.addEventListener('submit',async (e)=>{e.preventDefault();const msgEl=document.getElementById('userGroupFormMsg');const groupId=document.getElementById('userGroupId').value;const name=document.getElementById('userGroupName').value;const description=document.getElementById('userGroupDescription').value;const memberCheckboxes=document.querySelectorAll('#userGroupMembers input[type="checkbox"]:checked');const memberIds=Array.from(memberCheckboxes).map(cb=>cb.value);try{if (groupId){await fetchJson(`/api/admin/user-groups/${groupId}`,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,description})});const group=allUserGroups.find(g=>g.id===groupId);const oldMemberIds=group?.memberIds||[];for (const oldId of oldMemberIds){if (!memberIds.includes(oldId)){await fetchJson(`/api/admin/user-groups/${groupId}/members/${oldId}`,{method:'DELETE'})}}for (const newId of memberIds){if (!oldMemberIds.includes(newId)){await fetchJson(`/api/admin/user-groups/${groupId}/members`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({userId:newId})})}}msgEl.textContent='用户组已更新'}else{const group=await fetchJson('/api/admin/user-groups',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,description})});for (const memberId of memberIds){await fetchJson(`/api/admin/user-groups/${group.id}/members`,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({userId:memberId})})}msgEl.textContent='用户组已创建'}setTimeout(()=>{msgEl.textContent=''},3000);document.getElementById('userGroupModal').classList.add('hidden');await loadUserGroupsList();await loadAllUsers()}catch (err){msgEl.textContent='操作失败：'+err.message}})}}export function renderWorkloadAlertConfig(){const config=state.workloadAlertConfig;if (!config) return;const enabledCheckbox=document.getElementById('workloadAlertEnabled');const thresholdInput=document.getElementById('workloadThreshold');const warningThresholdInput=document.getElementById('warningThreshold');const criticalThresholdInput=document.getElementById('criticalThreshold');const silencePeriodInput=document.getElementById('silencePeriodMinutes');const messageTemplateWarning=document.getElementById('messageTemplateWarning');const messageTemplateCritical=document.getElementById('messageTemplateCritical');const channelCheckboxes=document.querySelectorAll('input[name="notifyChannel"]');if (enabledCheckbox) enabledCheckbox.checked=config.enabled||false;if (thresholdInput) thresholdInput.value=config.threshold||5;if (warningThresholdInput) warningThresholdInput.value=config.warningThreshold||0.8;if (criticalThresholdInput) criticalThresholdInput.value=config.criticalThreshold||1.0;if (silencePeriodInput) silencePeriodInput.value=config.silencePeriodMinutes||30;if (messageTemplateWarning&&config.messageTemplate){messageTemplateWarning.value=config.messageTemplate.warning||''}if (messageTemplateCritical&&config.messageTemplate){messageTemplateCritical.value=config.messageTemplate.critical||''}if (channelCheckboxes){channelCheckboxes.forEach(cb=>{cb.checked=(config.notifyChannels||[]).includes(cb.value)})}updateNextCheckTimeDisplay()}function updateNextCheckTimeDisplay(){const nextCheckEl=document.getElementById('nextCheckTime');if (!nextCheckEl) return;if (state.workloadAlertConfig?.enabled){const now=Date.now();const nextCheck=now+(5*60*1000);const nextTime=new Date(nextCheck).toLocaleTimeString('zh-CN');nextCheckEl.textContent=`下次检查:${nextTime}`}else{nextCheckEl.textContent='预警已禁用'}}export function renderWorkloadAlertHistory(){const{workloadAlertHistory}=getAdminElements();if (!workloadAlertHistory) return;const history=state.workloadAlertHistory||[];if (history.length===0){workloadAlertHistory.innerHTML='<div class="muted small">暂无预警记录</div>';return}workloadAlertHistory.innerHTML=history.map(item=>`<div class="workload-alert-item"><div class="workload-alert-info"><span class="workload-alert-level ${item.level}">${item.level==='warning'?'警告':'严重'}</span><span>${escapeHtml(item.agentName)}</span><span>负载:${item.workload}</span></div><div class="workload-alert-time muted small">${formatDate(item.triggeredAt)}</div></div>`).join('')}function initChannelFormHandlers(){const saveBtn=document.getElementById('saveWorkloadAlertConfigBtn');if (saveBtn){saveBtn.addEventListener('click',async ()=>{const enabledCheckbox=document.getElementById('workloadAlertEnabled');const thresholdInput=document.getElementById('workloadThreshold');const warningThresholdInput=document.getElementById('warningThreshold');const criticalThresholdInput=document.getElementById('criticalThreshold');const silencePeriodInput=document.getElementById('silencePeriodMinutes');const messageTemplateWarning=document.getElementById('messageTemplateWarning');const messageTemplateCritical=document.getElementById('messageTemplateCritical');const channelCheckboxes=document.querySelectorAll('input[name="notifyChannel"]:checked');const notifyChannels=Array.from(channelCheckboxes).map(cb=>cb.value);const payload={enabled:enabledCheckbox?.checked||false,threshold:parseInt(thresholdInput?.value||'5',10),warningThreshold:parseFloat(warningThresholdInput?.value||'0.8'),criticalThreshold:parseFloat(criticalThresholdInput?.value||'1.0'),silencePeriodMinutes:parseInt(silencePeriodInput?.value||'30',10),messageTemplate:{warning:messageTemplateWarning?.value||'',critical:messageTemplateCritical?.value||''},notifyChannels};try{await saveWorkloadAlertConfig(payload);state.workloadAlertConfig=payload;const msgEl=document.getElementById('workloadAlertMsg');if (msgEl){msgEl.textContent='配置已保存';setTimeout(()=>{msgEl.textContent=''},3000)}updateNextCheckTimeDisplay()}catch (err){alert('保存失败:'+err.message)}})}}export function initAdminComponent(){return{renderAdminUI,loadAllUsers,loadUserGroupsList,renderWorkloadAlertConfig,renderWorkloadAlertHistory}}